 60→class StatsFragment : Fragment(R.layout.stats_fragment), ScrollableViewInitializedListener {
 61→    @Inject
 62→    lateinit var uiHelpers: UiHelpers
 63→
 64→    @Inject
 65→    lateinit var jetpackBrandingUtils: JetpackBrandingUtils
 66→
 67→    @Inject
 68→    lateinit var mStatsTrafficSubscribersTabFeatureConfig: StatsTrafficSubscribersTabFeatureConfig
 69→
 70→    private val viewModel: StatsViewModel by activityViewModels()
 71→    private lateinit var swipeToRefreshHelper: SwipeToRefreshHelper
 72→    private lateinit var selectedTabListener: SelectedTabListener
 73→
 74→    private var restorePreviousSearch = false
 75→
 76→    private var binding: StatsFragmentBinding? = null
 77→
 78→    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
 79→        super.onViewCreated(view, savedInstanceState)
 80→
 81→        val nonNullActivity = requireActivity()
 82→        with(StatsFragmentBinding.bind(view)) {
 83→            binding = this
 84→            with(nonNullActivity as AppCompatActivity) {
 85→                setSupportActionBar(toolbar)
 86→                supportActionBar?.let {
 87→                    it.setHomeButtonEnabled(true)
 88→                    it.setDisplayHomeAsUpEnabled(true)
 89→                }
 90→            }
 91→            initializeViewModels(nonNullActivity, savedInstanceState == null, savedInstanceState)
 92→            initializeViews()
 93→        }
 94→    }
 95→
 96→    override fun onSaveInstanceState(outState: Bundle) {
 97→        outState.putInt(WordPress.LOCAL_SITE_ID, activity?.intent?.getIntExtra(WordPress.LOCAL_SITE_ID, 0) ?: 0)
 98→        viewModel.onSaveInstanceState(outState)
 99→        super.onSaveInstanceState(outState)
100→    }
