102→    private fun StatsFragmentBinding.initializeViews() {
103→        statsTrafficTabEnabled = mStatsTrafficSubscribersTabFeatureConfig.isEnabled()
104→
105→        val adapter = StatsPagerAdapter(this@StatsFragment)
106→        statsPager.adapter = adapter
107→        statsPager.setPageTransformer(
108→            MarginPageTransformer(resources.getDimensionPixelSize(R.dimen.margin_extra_large))
109→        )
110→        statsPager.offscreenPageLimit = 2
111→        selectedTabListener = SelectedTabListener(viewModel)
112→        TabLayoutMediator(tabLayout, statsPager) { tab, position ->
113→            tab.text = adapter.getTabTitle(position)
114→        }.attach()
115→        tabLayout.addOnTabSelectedListener(selectedTabListener)
116→
117→        swipeToRefreshHelper = WPSwipeToRefreshHelper.buildSwipeToRefreshHelper(pullToRefresh) {
118→            viewModel.onPullToRefresh()
119→        }
120→        disabledView.statsDisabledView.button.setOnClickListener {
121→            viewModel.onEnableStatsModuleClick()
122→        }
123→    }
