166→    private fun StatsFragmentBinding.setupObservers(activity: FragmentActivity) {
167→        viewModel.isRefreshing.observe(viewLifecycleOwner) {
168→            it?.let { isRefreshing ->
169→                swipeToRefreshHelper.isRefreshing = isRefreshing
170→            }
171→        }
172→
173→        viewModel.showSnackbarMessage.observe(viewLifecycleOwner) { holder ->
174→            showSnackbar(activity, holder)
175→        }
176→
177→        viewModel.toolbarHasShadow.observe(viewLifecycleOwner) { hasShadow ->
178→            appBarLayout.showShadow(hasShadow == true)
179→        }
180→
181→        viewModel.siteChanged.observeEvent(viewLifecycleOwner) { siteUpdateResult ->
182→            when (siteUpdateResult) {
183→                is SiteUpdateResult.SiteConnected -> viewModel.onSiteChanged()
184→                is SiteUpdateResult.NotConnectedJetpackSite -> getActivity()?.finish()
185→            }
186→        }
187→
188→        viewModel.hideToolbar.observeEvent(viewLifecycleOwner) { hideToolbar ->
189→            appBarLayout.setExpanded(!hideToolbar, true)
190→        }
191→
192→        viewModel.selectedSection.observe(viewLifecycleOwner) { selectedSection ->
193→            selectedSection?.let {
194→                if (statsTrafficTabEnabled) {
195→                    handleSelectedSectionWithTrafficTab(selectedSection)
196→                } else {
197→                    handleSelectedSection(selectedSection)
198→                }
199→            }
200→        }
201→
202→        viewModel.statsModuleUiModel.observeEvent(viewLifecycleOwner) { event ->
203→            updateUi(event)
204→        }
205→    }
