227→    @Suppress("MagicNumber")
228→    private fun StatsFragmentBinding.handleSelectedSectionWithTrafficTab(
229→        selectedSection: StatsSection
230→    ) {
231→        val position = when (selectedSection) {
232→            TRAFFIC -> 0
233→            INSIGHTS -> 1
234→            SUBSCRIBERS -> 2
235→            DETAIL,
236→            INSIGHT_DETAIL,
237→            TOTAL_LIKES_DETAIL,
238→            TOTAL_COMMENTS_DETAIL,
239→            TOTAL_FOLLOWERS_DETAIL,
240→            ANNUAL_STATS -> null
241→            else -> null
242→        }
243→        position?.let {
244→            if (statsPager.currentItem != position) {
245→                tabLayout.removeOnTabSelectedListener(selectedTabListener)
246→                statsPager.setCurrentItem(position, false)
247→                tabLayout.addOnTabSelectedListener(selectedTabListener)
248→            }
249→        }
250→    }
251→
252→    @Suppress("MagicNumber")
253→    private fun StatsFragmentBinding.handleSelectedSection(
254→        selectedSection: StatsSection
255→    ) {
256→        val position = when (selectedSection) {
257→            INSIGHTS -> 0
258→            DAYS -> 1
259→            WEEKS -> 2
260→            MONTHS -> 3
261→            YEARS -> 4
262→            DETAIL,
263→            INSIGHT_DETAIL,
264→            TOTAL_LIKES_DETAIL,
265→            TOTAL_COMMENTS_DETAIL,
266→            TOTAL_FOLLOWERS_DETAIL,
267→            ANNUAL_STATS -> null
268→            else -> null
269→        }
270→        position?.let {
271→            if (statsPager.currentItem != position) {
272→                tabLayout.removeOnTabSelectedListener(selectedTabListener)
273→                statsPager.setCurrentItem(position, false)
274→                tabLayout.addOnTabSelectedListener(selectedTabListener)
275→            }
276→        }
277→    }
