 63→    override fun stripUrl(uri: UriWrapper): String {
 64→        return buildString {
 65→            val offset = if (uri.host == STATS_PATH) {
 66→                append(APPLINK_SCHEME)
 67→                0
 68→            } else {
 69→                append("$HOST_WORDPRESS_COM/")
 70→                1
 71→            }
 72→            append(STATS_PATH)
 73→            val pathSegments = uri.pathSegments
 74→            val size = pathSegments.size
 75→            val statsTimeframe = if (size > offset) pathSegments.getOrNull(offset) else null
 76→            val hasSiteUrl = if (size > offset + 1) pathSegments.getOrNull(offset + 1) != null else false
 77→            if (statsTimeframe != null) {
 78→                append("/$statsTimeframe")
 79→            }
 80→            if (hasSiteUrl) {
 81→                append("/$SITE_DOMAIN")
 82→            }
 83→        }
 84→    }
